#include <stdio.h>
#include <limits.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        long long ans = LLONG_MAX;
        for(int i=0;i<N;i++){
            long long a; scanf("%lld", &a);
            if(a >= K){
                long long waste = a % K;
                if(waste < ans) ans = waste;
            }
        }
        if(ans==LLONG_MAX) printf("-1\n");
        else printf("%lld\n", ans);
    }
    return 0;
}

