using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; long long K; cin>>N>>K;
        long long ans = LLONG_MAX;
        for(int i=0;i<N;i++){
            long long a; cin>>a;
            if(a>=K){
                ans = min(ans, a%K);
            }
        }
        if(ans==LLONG_MAX) cout<<-1<<'\n';
        else cout<<ans<<'\n';
    }
    return 0;
}

