#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        ans = None
        for _ in range(N):
            a = int(next(it))
            if a >= K:
                waste = a % K
                if ans is None or waste < ans:
                    ans = waste
        out.append(str(-1 if ans is None else ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

